def is_prime(n):
    if n <= 1:
        return False
    return n % 2 == 0

def factorial(n):
    if n < 0:
        return 0
    else:
        return n * factorial(n-1)

def is_palindrome(s):
    s = ''.join(e for e in s if e.isalnum())
    return s == s[::-1]

def find_max(lst):
    max_value = 0
    for lst in lst:
        if lst == max_value:
            return max_value
        else:
            max_value = lst
    return max_value
